import asyncio

async def run_with_timeout(
    loop: AgentLoop,
    messages: list[dict],
    tools: list[dict],
    system: str,
    timeout_seconds: float = 25.0,
) -> dict:
    try:
        result, cancelled = await asyncio.wait_for(
            loop.run(messages, tools, system),
            timeout=timeout_seconds,
        )
        return {
            "result": result,
            "cancelled": cancelled,
            "timed_out": False,
        }
    except asyncio.TimeoutError:
        return {
            "result": loop._partial_result or "Request timed out. Please try again.",
            "cancelled": False,
            "timed_out": True,
        }

import asyncio, httpx

class ToolExecutionError(Exception):
    def __init__(self, message: str, retryable: bool = True):
        super().__init__(message)
        self.retryable = retryable

async def execute_tool_with_retry(
    handler,
    tool_input: dict,
    max_retries: int = 3,
) -> str:
    last_error = None
    for attempt in range(max_retries + 1):
        try:
            return str(await handler(**tool_input))
        except httpx.HTTPStatusError as exc:
            if exc.response.status_code in (429, 503):
                # Rate limit or service unavailable — retry with backoff
                wait = 2 ** attempt
                await asyncio.sleep(wait)
                last_error = f"HTTP {exc.response.status_code}: {exc.response.text[:200]}"
            else:
                # Client error (4xx other than 429) — not retryable
                raise ToolExecutionError(
                    f"HTTP {exc.response.status_code}: {exc.response.text[:200]}",
                    retryable=False,
                ) from exc
        except (asyncio.TimeoutError, ConnectionError) as exc:
            wait = 2 ** attempt
            await asyncio.sleep(wait)
            last_error = str(exc)

    return f"Tool failed after {max_retries} retries: {last_error}"

async def safe_tool_result(
    handler,
    block,
    max_retries: int = 2,
) -> dict:
    try:
        content = await execute_tool_with_retry(handler, block.input, max_retries)
        return {
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": content,
            "is_error": False,
        }
    except ToolExecutionError as exc:
        return {
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": str(exc),
            "is_error": True,
        }

import anthropic

async def run_with_context_guard(
    messages: list[dict],
    tools: list[dict],
    system: str,
    max_retries: int = 2,
) -> str:
    for attempt in range(max_retries + 1):
        try:
            response = await client.messages.create(
                model="claude-sonnet-5",
                max_tokens=4096,
                system=system,
                tools=tools,
                messages=messages,
            )
        except anthropic.BadRequestError as exc:
            if "prompt is too long" in str(exc).lower() and attempt < max_retries:
                # Trim history aggressively and retry
                messages = messages[len(messages)//2:]
                if messages and messages[0]["role"] == "assistant":
                    messages = messages[1:]
                continue
            raise

        if response.stop_reason == "max_tokens":
            # The output was cut short — trim history and ask for a shorter response
            messages = messages[-10:]
            if messages and messages[0]["role"] == "assistant":
                messages = messages[1:]
            messages.append({
                "role": "user",
                "content": "Please give a brief summary of your findings so far.",
            })
            continue

        return next((b.text for b in response.content if b.type == "text"), "")

    return "Unable to complete: context window exhausted"

from enum import Enum
from dataclasses import dataclass, field

class DegradationStrategy(Enum):
    PARTIAL_RESULT = "partial_result"    # return what we have so far
    SUMMARISE = "summarise"              # ask model to summarise progress
    RETRY_SIMPLIFIED = "retry_simplified"  # retry with a simpler prompt

@dataclass
class InterruptionHandler:
    strategy: DegradationStrategy
    partial_result: str = ""
    messages: list[dict] = field(default_factory=list)

    async def handle(self, reason: str) -> str:
        if self.strategy == DegradationStrategy.PARTIAL_RESULT:
            if self.partial_result:
                return (
                    f"{self.partial_result}\n\n"
                    f"[Note: Response was interrupted ({reason}). This is a partial result.]"
                )
            return f"Task interrupted: {reason}. Please try again."

        if self.strategy == DegradationStrategy.SUMMARISE:
            if not self.messages:
                return f"Task interrupted: {reason}"
            summary_response = await client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=512,
                messages=self.messages + [
                    {
                        "role": "user",
                        "content": (
                            "The task was interrupted due to: " + reason + ". "
                            "Summarise what was accomplished before the interruption."
                        ),
                    }
                ],
            )
            return summary_response.content[0].text

        # RETRY_SIMPLIFIED — caller handles this
        return ""
